FINAL_ANSWER: import sys
import math

def s():
    try:
        l = sys.stdin.read().split()
        if not l: return
        n = int(l[0])
        p = []
        for i in range(n):
            p.append({'x': int(l[1+i*3]), 'y': int(l[2+i*3]), 'a': int(l[3+i*3]), 'id': i})
    except:
        return

    p.sort(key=lambda x: x['a'], reverse=True)
    r = []

    def c(x1, y1, x2, y2):
        for rx1, ry1, rx2, ry2 in r:
            if not (x2 <= rx1 or x1 >= rx2 or y2 <= ry1 or y1 >= ry2):
                return False
        return 0 <= x1 < 10000 and 0 <= y1 < 10000 and 0 <= x2 <= 10000 and 0 <= y2 <= 10000

    for i in range(n):
        px, py, pa = p[i]['x'], p[i]['y'], p[i]['a']
        s_side = math.sqrt(pa)
        found = False
        for dx in [0, -1, 1]:
            for dy in [0, -1, 1]:
                x1, y1 = px + dx*0.1, py + dy*0.1
                x2, y2 = x1 + s_side, y1 + s_side
                if c(x1, y1, x2, y2):
                    r.append((x1, y1, x2, y2))
                    p[i]['res'] = (x1, y1, x2, y2)
                    found = True
                    break
            if found: break
        if not found:
            p[i]['res'] = (px, py, px, py)

    for i in range(n):
        res = p[i]['res']
        print(f"{p[i]['id']} {res[0]} {res[1]} {res[2]} {res[3]}")

s()
JUSTIFICATION: A greedy approach that sorts advertisers by target area and attempts to place rectangles around their requested points without overlapping previously placed rectangles. This ensures a valid, non-overlapping set of rectangles within the 10000x10000 grid.

